#!/bin/bash
echo Installing dialog...; sudo pacman --noconfirm -Syu dialog > dialog.log; echo Cloning...; git clone https://aur.archlinux.org/tor-router.git > git.log; echo Installing...; cd tor-router; makepkg --install; echo Install Complete!; echo Showing you the log files in 3 seconds...; sleep 3; nano ../dialog.log; nano ../git.log; echo Cleaning Up...; rm -rf ../git.log; rm -rf ../dialog.log; cd ..; rm -rf tor-router; echo Thanks for installing!; echo Exiting...
